const configBinary = await this.helpers.getBinaryDataBuffer(0, 'data');
const config = JSON.parse(configBinary.toString());
const chatId = String(config.default_chat_id || '');

const error = $('Error Trigger').first().json;

// Escape legacy Markdown control chars (_ * ` [) in interpolated values so
// error strings containing backticks or brackets don't break Telegram parsing.
const esc = (s) => String(s ?? '').replace(/([_*`\[])/g, '\\$1');

const workflowName = esc(error.workflow?.name);
const nodeName = esc(error.execution?.lastNodeExecuted);
const errorMsg = esc(error.execution?.error?.message);
const ts = new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris' });

// Surface the raw API response detail when present. n8n's NodeApiError
// preserves the raw response body in error.messages[0], typically as a
// string like "400 - {\"ok\":false,\"error_code\":400,\"description\":\"...\"}".
// Parsing out the description gives the actual cause; surfacing the
// error_code as a [400] / [429] / [5xx] prefix gives an instant visual
// cue for the failure category (client bug vs auth vs rate limit vs
// upstream outage). Backward-compatible: when messages[0] is absent,
// no Detail line is added and the alert keeps its previous shape.
let detail = '';
const rawDetail = error.execution?.error?.messages?.[0];
if (rawDetail) {
  let description = String(rawDetail);
  let errorCode = null;
  const jsonStart = description.indexOf('{');
  if (jsonStart !== -1) {
    try {
      const body = JSON.parse(description.slice(jsonStart));
      if (body.description) description = body.description;
      if (body.error_code) errorCode = body.error_code;
    } catch (_) {
      // Tail wasn't valid JSON, fall back to the full raw string
    }
  }
  let extracted = errorCode ? `[${errorCode}] ${description}` : description;
  if (extracted.length > 400) extracted = extracted.slice(0, 397) + '…';
  detail = `\n*Detail:* ${esc(extracted)}`;
}

return [{
  json: {
    chat_id: chatId,
    text: `⚠️ *Workflow error*\n\n*Workflow:* ${workflowName}\n*Node:* ${nodeName}\n*Error:* ${errorMsg}${detail}\n\n_${ts}_`
  }
}];
